Author: Ying Liu <yingliufb@fb.com>
Date:   Mon May 9 16:36:22 2022 -0700

    Update Velox bucketize to use lower_bound (#318)

    Summary:
    Pull Request resolved: https://github.com/facebookresearch/torcharrow/pull/318

    Instead of using a custom binary search, use std::lower_bound

    Reviewed By: wenleix, tgalkovskyi

    Differential Revision: D36214673

    fbshipit-source-id: 772febc48f26a3bfc6572baf36cc76ae43525fa8
---
 csrc/velox/functions/rec/bucketize.h | 14 +++++---------
 1 file changed, 5 insertions(+), 9 deletions(-)

diff --git a/csrc/velox/functions/rec/bucketize.h b/csrc/velox/functions/rec/bucketize.h
index f170f960..5cd49e11 100644
--- a/csrc/velox/functions/rec/bucketize.h
+++ b/csrc/velox/functions/rec/bucketize.h
@@ -41,16 +41,12 @@ inline void validateBordersSpec(const T1& borders) {

 template <typename T1, typename T2>
 inline int32_t computeBucketId(const T1& borders, const T2& val) {
-  int32_t index = borders.size();
-  auto jump = borders.size();
-
-  while (jump > 0) {
-    while (index - jump >= 0 && val <= borders[index - jump]) {
-      index -= jump;
-    }
-    jump /= 2;
+  int32_t index =
+      std::lower_bound(borders.begin(), borders.end(), val) - borders.begin();
+  if (index >= borders.size() - 1) {
+    return index;
   }
-  return index;
+  return val < borders[index + 1] ? index : index + 1;
 }

